CANVAS WORLD RENDERER (crates/scriptbots-render/src/lib.rs)
═══════════════════════════════════════════════════════════════════════

RenderFrame Structure:
```rust
struct RenderFrame {
    world_size: (f32, f32),              // World dimensions
    food_dimensions: (u32, u32),         // Grid size (cells)
    food_cell_size: u32,                 // Cell size (world units)
    food_cells: Vec<f32>,                // Food values (row-major)
    food_max: f32,                       // Max food per cell
    agents: Vec<AgentRenderData>,        // Agent snapshots
    agent_base_radius: f32,              // Base render size
}

struct AgentRenderData {
    position: Vec2,
    color: [f32; 3],
    spike_length: f32,
    health: f32,
}
```

Frame extraction from WorldState:
```rust
impl RenderFrame {
    fn snapshot(world: &WorldState) -> Option<Self> {
        let config = world.config();
        let (width, height) = config.food_dimensions().ok()?;
        let food = world.food_grid();
        let columns = world.agents().columns();

        // Extract agent data in parallel
        let agents: Vec<AgentRenderData> = columns
            .positions()
            .iter()
            .enumerate()
            .map(|(idx, position)| AgentRenderData {
                position: *position,
                color: columns.colors()[idx],
                spike_length: columns.spike_lengths()[idx],
                health: columns.health()[idx],
            })
            .collect();

        Some(Self {
            world_size: (config.world_width as f32, config.world_height as f32),
            food_dimensions: (width, height),
            food_cell_size: config.food_cell_size,
            food_cells: food.cells().to_vec(),
            food_max: config.food_max,
            agents,
            agent_base_radius: (config.spike_radius * 0.5).max(12.0),
        })
    }
}
```

Snapshot benefits:
- Decouples rendering from world lock (snapshot taken once per frame)
- Immutable data structure (safe to pass between threads)
- Minimal data (only render-relevant fields)

Painting Algorithm:
```rust
fn paint_frame(frame: &RenderFrame, camera: &CameraState,
               bounds: Bounds<Pixels>, window: &mut Window) {
    // 1. Calculate coordinate transform
    let world_w = frame.world_size.0;
    let world_h = frame.world_size.1;
    let bounds_w = f32::from(bounds.size.width);
    let bounds_h = f32::from(bounds.size.height);

    // Fit world to canvas (letterbox if aspect ratios differ)
    let base_scale = (bounds_w / world_w).min(bounds_h / world_h);
    let scale = base_scale * camera.zoom;

    // Center world in canvas
    let render_w = world_w * scale;
    let render_h = world_h * scale;
    let pad_x = (bounds_w - render_w) * 0.5;
    let pad_y = (bounds_h - render_h) * 0.5;

    // Apply camera offset
    let offset_x = bounds.origin.x + pad_x + camera.offset_px.0;
    let offset_y = bounds.origin.y + pad_y + camera.offset_px.1;

    // 2. Paint background (dark blue-gray)
    window.paint_quad(fill(bounds, Background::from(Rgba {
        r: 0.03, g: 0.05, b: 0.08, a: 1.0
    })));

    // 3. Paint food cells
    let cell_world = frame.food_cell_size as f32;
    let cell_px = cell_world * scale;

    for y in 0..frame.food_dimensions.1 {
        for x in 0..frame.food_dimensions.0 {
            let value = frame.food_cells[y * frame.food_dimensions.0 + x];
            if value <= 0.001 { continue; }  // Skip empty cells

            let intensity = (value / frame.food_max).clamp(0.0, 1.0);
            let color = food_color(intensity);

            let px_x = offset_x + (x as f32 * cell_world * scale);
            let px_y = offset_y + (y as f32 * cell_world * scale);
            let cell_bounds = Bounds::new(
                point(px(px_x), px(px_y)),
                size(px(cell_px), px(cell_px))
            );
            window.paint_quad(fill(cell_bounds, Background::from(color)));
        }
    }

    // 4. Paint agents
    for agent in &frame.agents {
        let px_x = offset_x + agent.position.x * scale;
        let px_y = offset_y + agent.position.y * scale;

        // Size based on spike length (bigger spikes = bigger visual)
        let dynamic_radius = (frame.agent_base_radius + agent.spike_length * 0.25).max(6.0);
        let size_px = (dynamic_radius * scale).max(2.0);

        let agent_bounds = Bounds::new(
            point(px(px_x - half), px(px_y - half)),
            size(px(size_px), px(size_px))
        );

        let color = agent_color(agent);
        window.paint_quad(fill(agent_bounds, Background::from(color)));
    }
}
```

Color Functions:
```rust
fn food_color(intensity: f32) -> Rgba {
    // Green tint, darker when depleted
    Rgba {
        r: 0.06 + 0.25 * intensity,
        g: 0.22 + 0.55 * intensity,  // Dominant green channel
        b: 0.12 + 0.25 * intensity,
        a: 0.2 + 0.45 * intensity,   // More opaque when plentiful
    }
}

fn agent_color(agent: &AgentRenderData) -> Rgba {
    // Agent base color modulated by health
    let health_factor = (agent.health / 2.0).clamp(0.35, 1.0);
    Rgba {
        r: agent.color[0] * health_factor,
        g: agent.color[1] * health_factor,
        b: agent.color[2] * health_factor,
        a: 0.9,
    }
}
```

Visual design:
- Food: Green gradient (sparse → dense)
- Agents: Genome color dimmed by low health
- Background: Dark to increase contrast
- Alpha blending: Subtle food cells, solid agents

