Test 2: Analytics Query Validation
```rust
#[test]
fn top_predators_tracks_average_energy() -> Result<(), Box<dyn std::error::Error>> {
    let mut storage = Storage::with_thresholds(&path, 1, 1, 1, 1)?;

    // Insert two snapshots of same agent
    storage.persist(&sample_batch(1, 1.0))?;
    storage.persist(&sample_batch(2, 3.0))?;
    storage.flush()?;

    let predators = storage.top_predators(4)?;
    let leader = &predators[0];

    // Should average energies: (1.0 + 3.0) / 2 = 2.0
    assert!((leader.avg_energy - 2.0).abs() < 1e-6);
    assert_eq!(leader.last_tick, 2);

    Ok(())
}
```

Test utilities:
```rust
fn temp_db_path(prefix: &str) -> PathBuf {
    let timestamp = SystemTime::now().duration_since(UNIX_EPOCH)
        .expect("time").as_nanos();
    std::env::temp_dir().join(format!(
        "{}-{}-{}.duckdb",
        prefix, std::process::id(), timestamp
    ))
}
```

Generates unique temp paths (prevents test collisions).

